import type { Locale } from 'date-fns';
import { format, isValid } from 'date-fns';

export type { Locale as DateLocale };

let defaultDateLocale: Locale | null = null;

/**
 * Set the default locale for formatDate.
 * @param locale - date-fns Locale object (e.g., import { ptBR } from 'date-fns/locale')
 */
export function setDefaultDateLocale(locale: Locale | null): void {
  defaultDateLocale = locale;
}

/**
 * Get the current default locale.
 */
export function getDefaultDateLocale(): Locale | null {
  return defaultDateLocale;
}

export type FormatDateOptions = {
  locale?: Locale;
};

/**
 * Format a date using date-fns.
 * @param date - Date object, ISO string, or timestamp
 * @param pattern - date-fns format pattern (e.g., 'yyyy-MM-dd', 'MMM dd, yyyy')
 * @param options - Optional locale override
 * @throws InvariantError if date is invalid
 *
 * @example
 * formatDate(new Date(), 'yyyy-MM-dd'); // '2025-12-15'
 * formatDate('2025-01-15', 'MMM dd'); // 'Jan 15'
 *
 * // With locale
 * import { ptBR } from 'date-fns/locale';
 * setDefaultDateLocale(ptBR);
 * formatDate(new Date(), 'MMMM'); // 'dezembro'
 *
 * // Override locale for single call
 * formatDate(new Date(), 'MMMM', { locale: enUS }); // 'December'
 */
export function formatDate(
  date: Date | string | number,
  pattern: string,
  options?: FormatDateOptions,
): string {
  if (typeof date === 'string' || typeof date === 'number') {
    date = new Date(date);
  }

  if (!isValid(date)) {
    throw new TypeError(`Invalid date: expected a valid Date, got ${date}`);
  }

  const locale = options?.locale ?? defaultDateLocale;

  return format(date, pattern, locale ? { locale } : undefined);
}

